class Board:
    def __init__(self):
        self.board = [
            ['b' if (i + j) % 2 else ' ' for i in range(8)] for j in range(8)
        ]
        self.initialize_board()

    def initialize_board(self):
        # Place pieces on the board
        for row in range(3):
            for col in range(8):
                if (row + col) % 2 == 0:
                    self.board[row][col] = 'b'
        for row in range(5, 8):
            for col in range(8):
                if (row + col) % 2 == 0:
                    self.board[row][col] = 'r'

    def get_piece(self, row, col):
        return self.board[row][col]

    def move_piece(self, start_row, start_col, end_row, end_col):
        piece = self.get_piece(start_row, start_col)
        if piece and (piece == 'b' or piece == 'B') and self.is_valid_move(start_row, start_col, end_row, end_col):
            self.board[start_row][start_col] = ' '
            self.board[end_row][end_col] = piece
            if piece == 'b' and end_row == 7:
                self.board[end_row][end_col] = 'B'
            elif piece == 'r' and end_row == 0:
                self.board[end_row][end_col] = 'R'

    def is_valid_move(self, start_row, start_col, end_row, end_col):
        piece = self.get_piece(start_row, start_col)
        if not piece or (piece != 'b' and piece != 'B' and piece != 'r' and piece != 'R'):
            return False
        if abs(end_row - start_row) == 1 and abs(end_col - start_col) == 1:
            if self.get_piece(end_row, end_col):
                return False
            return True
        if abs(end_row - start_row) == 2 and abs(end_col - start_col) == 2:
            intermediate_row = (start_row + end_row) // 2
            intermediate_col = (start_col + end_col) // 2
            captured_piece = self.get_piece(intermediate_row, intermediate_col)
            if not captured_piece or (piece == 'r' and captured_piece != 'b') and (piece == 'b' and captured_piece != 'r'):
                return False
            if not self.get_piece(end_row, end_col):
